/// Returns true if `name_lc` (already lowercased) is a compiler-intrinsic global.
pub fn is_global_builtin(name_lc: &str) -> bool {
    GLOBAL_BUILTIN_METHODS.contains(name_lc)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn catalog_spot_checks() {
        assert!(
            is_global_builtin("guiallowed"),
            "GuiAllowed must be in catalog"
        );
        assert!(is_global_builtin("strlen"), "StrLen must be in catalog");
        assert!(
            is_global_builtin("strsubstno"),
            "StrSubstNo must be in catalog"
        );
        assert!(
            is_global_builtin("createguid"),
            "CreateGuid must be in catalog"
        );
        assert!(is_global_builtin("format"), "Format must be in catalog");
        assert!(
            !is_global_builtin("thisisnotarealglobalxyz123"),
            "nonsense name must be absent"
        );
    }
}
